#include <iostream>
#include <string>

// Function with pointer parameter
void modifyWithPointer(int* ptr) {
    if (ptr != nullptr) {
        *ptr = 999;
    }
}

// Function with reference parameter
void modifyWithReference(int& ref) {
    ref = 999;
}

// Function that returns a reference
int& getLargest(int& a, int& b) {
    return (a > b) ? a : b;
}

int main() {
    std::cout << "=== References vs Pointers ===" << std::endl;

    // 1. References are aliases
    std::cout << "\n--- References are aliases ---" << std::endl;
    int health = 100;
    int& healthRef = health;  // healthRef is an alias for health

    std::cout << "health: " << health << std::endl;
    std::cout << "healthRef: " << healthRef << std::endl;

    healthRef = 150;
    std::cout << "After healthRef = 150, health: " << health << std::endl;

    // 2. References vs Pointers - key differences
    std::cout << "\n--- Key Differences ---" << std::endl;
    int score = 50;
    int& scoreRef = score;   // Must be initialized
    int* scorePtr = &score;  // Can be nullptr

    std::cout << "score: " << score << std::endl;
    std::cout << "scoreRef: " << scoreRef << std::endl;
    std::cout << "*scorePtr: " << *scorePtr << std::endl;

    // 3. Using references to avoid copying
    std::cout << "\n--- Passing by reference ---" << std::endl;
    int value = 10;
    std::cout << "Before: " << value << std::endl;
    modifyWithPointer(&value);  // Pass pointer
    std::cout << "After pointer: " << value << std::endl;
    modifyWithReference(value);  // Pass reference
    std::cout << "After reference: " << value << std::endl;

    // 4. Returning references
    std::cout << "\n--- Returning references ---" << std::endl;
    int a = 5, b = 10;
    int& largest = getLargest(a, b);
    std::cout << "Largest: " << largest << std::endl;
    largest = 99;
    std::cout << "a: " << a << ", b: " << b << std::endl;

    // 5. When to use what
    std::cout << "\n--- When to use what ---" << std::endl;
    std::cout << "Use references when:" << std::endl;
    std::cout << "  - You need an alias for a variable" << std::endl;
    std::cout << "  - You want to pass by reference (avoid copying)" << std::endl;
    std::cout << "  - You know the variable always exists" << std::endl;
    std::cout << "Use pointers when:" << std::endl;
    std::cout << "  - You need to point to nothing (nullptr)" << std::endl;
    std::cout << "  - You need pointer arithmetic" << std::endl;
    std::cout << "  - You need to reassign to point to different things" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>

int main() {
    int* ptr = nullptr;
    int& ref = *ptr;  // ERROR! Cannot reference null

    std::cout << ref << std::endl;
    return 0;
}

phase2.explanation:
You tried to create a reference to a null pointer!

**What's happening:**
1. `ptr` is `nullptr`
2. `*ptr` dereferences null (undefined behavior)
3. `ref` tries to reference the null value
4. **CRASH!**

**The fix:**
```cpp
int* ptr = nullptr;
if (ptr != nullptr) {
    int& ref = *ptr;  // Safe
} else {
    std::cout << "ptr is null!" << std::endl;
}
```

**PlusPlus-chan says:**
"References must always refer to a valid object. Never try to reference null."

