#include <iostream>

void doubleValue(int& value) {
    value *= 2;
}

int main() {
    int x = 10;
    int& refX = x;
    int* ptrX = &x;

    std::cout << "Initial values:" << std::endl;
    std::cout << "x: " << x << ", refX: " << refX << ", *ptrX: " << *ptrX << std::endl;

    refX = 20;
    std::cout << "After refX = 20:" << std::endl;
    std::cout << "x: " << x << ", refX: " << refX << ", *ptrX: " << *ptrX << std::endl;

    *ptrX = 30;
    std::cout << "After *ptrX = 30:" << std::endl;
    std::cout << "x: " << x << ", refX: " << refX << ", *ptrX: " << *ptrX << std::endl;

    doubleValue(x);
    std::cout << "After doubleValue(x): " << x << std::endl;

    return 0;
}
